package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

public class CSVPrinterTest {

    private CSVPrinter printer;
    private Appendable out;
    private CSVFormat format;

    @BeforeEach
    public void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    public void testPrint_NewRecordFalse_Quoting() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Arrange
        setNewRecord(printer, false);
        when(format.getDelimiter()).thenReturn(',');
        when(format.isQuoting()).thenReturn(true);
        when(format.isEscaping()).thenReturn(false);

        String value = "value";
        int offset = 0;
        int len = value.length();

        // Spy on printer to verify private printAndQuote call
        CSVPrinter spyPrinter = spy(printer);

        // Act
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(spyPrinter, "object", value, offset, len);

        // Assert
        verify(out).append(',');
        verify(spyPrinter).printAndQuote("object", value, offset, len);
        assertFalse(getNewRecord(spyPrinter));
    }

    @Test
    public void testPrint_NewRecordTrue_Quoting() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Arrange
        setNewRecord(printer, true);
        when(format.isQuoting()).thenReturn(true);
        when(format.isEscaping()).thenReturn(false);

        String value = "val";
        int offset = 0;
        int len = value.length();

        CSVPrinter spyPrinter = spy(printer);

        // Act
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(spyPrinter, "obj", value, offset, len);

        // Assert
        verify(out, never()).append(anyChar());
        verify(spyPrinter).printAndQuote("obj", value, offset, len);
        assertFalse(getNewRecord(spyPrinter));
    }

    @Test
    public void testPrint_NewRecordFalse_Escaping() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Arrange
        setNewRecord(printer, false);
        when(format.getDelimiter()).thenReturn(';');
        when(format.isQuoting()).thenReturn(false);
        when(format.isEscaping()).thenReturn(true);

        String value = "escapeTest";
        int offset = 1;
        int len = 4;

        CSVPrinter spyPrinter = spy(printer);

        // Act
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(spyPrinter, "obj", value, offset, len);

        // Assert
        verify(out).append(';');
        verify(spyPrinter).printAndEscape(value, offset, len);
        assertFalse(getNewRecord(spyPrinter));
    }

    @Test
    public void testPrint_NewRecordTrue_NoQuotingNoEscaping() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Arrange
        setNewRecord(printer, true);
        when(format.isQuoting()).thenReturn(false);
        when(format.isEscaping()).thenReturn(false);

        String value = "abcdef";
        int offset = 2;
        int len = 3;

        // Act
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);
        printMethod.invoke(printer, "obj", value, offset, len);

        // Assert
        verify(out).append(value, offset, offset + len);
        assertFalse(getNewRecord(printer));
    }

    // Helper to set private boolean newRecord field
    private void setNewRecord(CSVPrinter printer, boolean value) {
        try {
            var field = CSVPrinter.class.getDeclaredField("newRecord");
            field.setAccessible(true);
            field.set(printer, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    // Helper to get private boolean newRecord field
    private boolean getNewRecord(CSVPrinter printer) {
        try {
            var field = CSVPrinter.class.getDeclaredField("newRecord");
            field.setAccessible(true);
            return field.getBoolean(printer);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
